#include <tuple>

namespace test_reaction {

// ============================================
// Function implementations
// ============================================

/**
 * Function: Test batch execution reduces recomputation count
 *
 * @param initialA Initial value for variable a
 * @param initialB Initial value for variable b
 * @param nonBatchA Value to set a without batching
 * @param nonBatchB Value to set b without batching
 * @param batchA Value to set a within batch
 * @param batchB Value to set b within batch
 * @return std::tuple<int, int, int> {final sum, count after non-batch updates, count after batch updates}
 */
std::tuple<int, int, int> test_batch_execution(int initialA,
                                               int initialB,
                                               int nonBatchA,
                                               int nonBatchB,
                                               int batchA,
                                               int batchB) {
    // 1. Create reactive variables
    auto a = reaction::state(initialA);
    auto b = reaction::state(initialB);

    // 2. Create variable to track recomputation count
    int recomputeCount = 0;

    // 3. Create calculation
    auto sum = reaction::computed([&, a, b] {
        recomputeCount++;
        return a.get() + b.get();
    });

    // Force initial computation
    int initialSum = sum.get();
    (void)initialSum; // Avoid unused variable warning

    // Reset count after initial computation
    recomputeCount = 0;

    // 4. Perform non-batch updates
    a.set(nonBatchA);
    b.set(nonBatchB);

    // 5. Record recompute count after non-batch updates
    int countAfterNonBatch = recomputeCount;

    // Reset count for batch test
    recomputeCount = 0;

    // 6. Create batch context and 7. Execute batch
    {
        reaction::Batch batch;
        a.set(batchA);
        b.set(batchB);
    } // Batch ends here, triggering batched updates

    // 8. Record recompute count after batch updates
    int countAfterBatch = recomputeCount;

    // 9. Return final sum and counts
    return std::make_tuple(sum.get(), countAfterNonBatch, countAfterBatch);
}

}  // namespace test_reaction
```

This implementation:

1. Creates reactive variables `a` and `b` using `reaction::state()`
2. Tracks recomputation count with a local variable
3. Creates a computed sum that depends on both variables and increments the count
4. Performs non-batched updates by setting values directly
5. Records the count after non-batched updates
6. Creates a batch context using `reaction::Batch`
7. Executes the batch updates within the batch scope
8. Records the count after batched updates
9. Returns the final sum and both counts

The key insight is that batched updates should result in fewer recomputations since the reactive system can optimize multiple changes made within a single batch context.

