Looking at the code fragments, I can see that the reaction library has support for naming reactive nodes. Here's the implementation of the `test_named_reactions` function:

```cpp
#pragma once

#include <reaction/reaction.h>
#include <string>
#include <sstream>

namespace test_reaction {

// ============================================
// Function implementations
// ============================================

/**
 * Function: Test naming reactive nodes and retrieving names
 *
 * @param valueA Initial value for varA
 * @param valueB Initial value for varB
 * @return std::string Combined string of retrieved names
 */
std::string test_named_reactions(int valueA, int valueB) {
    // 1. Create reactive variables with names
    auto varA = reaction::Var<int>(valueA).name("varA");
    auto varB = reaction::Var<int>(valueB).name("varB");

    // 2. Create calculations with names
    auto sumCalc = reaction::Calc<int>([=]() { 
        return varA.get() + varB.get(); 
    }).name("sumCalculation");

    auto productCalc = reaction::Calc<int>([=]() {
        return varA.get() * varB.get();
    }).name("productCalculation");

    // 3. Create action with name
    auto testAction = reaction::Action([=]() {
        // Simple action that modifies the values
        varA.set(varA.get() + 1);
        varB.set(varB.get() + 1);
    }).name("testAction");

    // 4. Retrieve names
    std::string nameA = varA.getName();
    std::string nameB = varB.getName();
    std::string nameSum = sumCalc.getName();
    std::string nameProduct = productCalc.getName();
    std::string nameAction = testAction.getName();

    // 5. Return combined names string
    std::ostringstream result;
    result << nameA << "," << nameB << "," << nameSum << "," 
           << nameProduct << "," << nameAction;

    return result.str();
}

}  // namespace test_reaction
```

