```cpp
#pragma once

#include <reaction/reaction.h>
#include <tuple>

namespace test_reaction {

// ============================================
// Function implementations
// ============================================

/**
 * Function: Test filter trigger with conditional recomputation
 *
 * @param initialValue Initial sensor value
 * @param firstUpdate First update (expected to be within threshold)
 * @param secondUpdate Second update (expected to exceed threshold)
 * @param diffThreshold Minimum delta to trigger recomputation
 * @param levelThreshold Threshold to categorize HIGH vs NORMAL
 * @return std::tuple<std::string, int, int>
 *         {final status string, recompute count after first update, recompute count after second update}
 */
std::tuple<std::string, int, int> test_filter_trigger(double initialValue,
                                                      double firstUpdate,
                                                      double secondUpdate,
                                                      double diffThreshold,
                                                      double levelThreshold) {
    // 1. Create reactive variable
    auto sensor = reaction::make_variable(initialValue);

    // 2. Create variables to track recomputation count and last processed value
    int recomputeCount = 0;
    double lastProcessedValue = initialValue;

    // 3. Create filter-triggered calculation
    auto statusCalc = reaction::computed([&]() -> std::string {
        double currentValue = sensor.get();

        // Check if the change exceeds the threshold
        if (std::abs(currentValue - lastProcessedValue) >= diffThreshold) {
            recomputeCount++;
            lastProcessedValue = currentValue;

            // Determine status based on level threshold
            if (currentValue > levelThreshold) {
                return "HIGH";
            } else {
                return "NORMAL";
            }
        }

        // Return previous status if change is below threshold
        if (lastProcessedValue > levelThreshold) {
            return "HIGH";
        } else {
            return "NORMAL";
        }
    });

    // Initialize the status
    std::string initialStatus = statusCalc.get();
    int countAfterFirst = 0;
    int countAfterSecond = 0;

    // 5. Update sensor with first value
    sensor.set(firstUpdate);

    // 6. Record recompute count after first update
    std::string statusAfterFirst = statusCalc.get();
    countAfterFirst = recomputeCount;

    // 7. Update sensor with second value
    sensor.set(secondUpdate);

    // 8. Record recompute count after second update
    std::string finalStatus = statusCalc.get();
    countAfterSecond = recomputeCount;

    // 9. Get final status
    // 10. Return final status and counts
    return std::make_tuple(finalStatus, countAfterFirst, countAfterSecond);
}

}  // namespace test_reaction
```

This implementation:

1. Creates a reactive variable `sensor` using `reaction::make_variable()`
2. Tracks recomputation count and last processed value
3. Uses `reaction::computed()` to create a filter-triggered calculation that only updates when the change exceeds `diffThreshold`
4. Applies the filter logic by checking the absolute difference between current and last processed values
5. Updates the sensor with the first value and records the recomputation count
6. Updates the sensor with the second value and records the updated count
7. Returns the final status along with both recomputation counts

The filter logic ensures that the status is only recomputed when the sensor value changes by at least `diffThreshold`, demonstrating the conditional recomputation behavior.

