namespace test_reaction {

struct ConstVarResult {
    int initialSum;
    int updatedSum;
};

inline ConstVarResult test_const_var_propagation(int baseValue, int constValue, int delta) {
    // 1. Create a mutable reactive variable
    auto mutableVar = reaction::var(baseValue);

    // 2. Create a constant reactive variable
    auto constVar = reaction::constant(constValue);

    // 3. Create a calculation that sums both variables
    auto sumCalc = reaction::calc([mutableVar, constVar]() {
