namespace test_reaction {

struct AlwaysTriggerResult {
    int recomputeCountAfterInit;
    int recomputeCountAfterDuplicateWrite;
};

inline AlwaysTriggerResult test_always_trigger(int initialValue) {
    int counter = 0;

    // Create a reactive variable
    auto var = reaction::Resource<int>::create(initialValue);

    // Create an AlwaysTrig calculation that doubles the value and increments counter
    auto calc = reaction::Expression<int, reaction::TriggerAlways>::create(
        [&counter, var]() -> int {
            counter++;
            return var->get() * 2;
        },
        var
    );

    // Force initial evaluation and store recompute count
    [[maybe_unused]] auto initialResult = calc->get();
    int countAfterInit = counter;

    // Write the same value again
    var->set(initialValue);

    // Force evaluation again and store recompute count
    [[maybe_unused]] auto duplicateResult = calc->get();
    int countAfterDuplicate = counter;

    // Force evaluation to avoid unused variable warnings
    (void)initialResult;
    (void)duplicateResult;

    return {countAfterInit, countAfterDuplicate};
}

}  // namespace test_reaction
