#include <chrono>

namespace test_reaction {

ThreadGuardState test_thread_guard() {
    // 1. Get thread manager instance
    auto& thread_manager = reaction::ThreadManager::getInstance();

    // 2. Reset thread manager state
    thread_manager.reset();

    // 3. Get thread safety status before guard
    bool safety_before = thread_manager.isThreadSafe();

    // 4. Get thread count before guard  
    std::size_t thread_count_before = thread_manager.getThreadCount();

    // 5. Create a worker thread with ThreadRegistrationGuard
    std::atomic<bool> worker_completed{false};

    auto worker_func = [&worker_completed]() {
        // This thread will be automatically registered by ThreadRegistrationGuard
        reaction::ThreadRegistrationGuard guard;
        // Simulate some work
        std::this_thread::sleep_for(std::chrono::milliseconds(10));
        worker_completed.store(true, std::memory_order_release);
    };

    std::thread worker_thread(worker_func);

    // 6. Wait for worker thread to complete
    worker_thread.join();

    // 7. Get thread safety status after guard
    bool safety_after = thread_manager.isThreadSafe();

    // 8. Get thread count after guard
    std::size_t thread_count_after = thread_manager.getThreadCount();

    // 9. Return thread guard state
    return ThreadGuardState{
        .safetyBeforeGuard = safety_before,
        .safetyAfterGuard = safety_after,
        .threadCountBeforeGuard = thread_count_before,
        .threadCountAfterGuard = thread_count_after
    };
}

}  // namespace test_reaction
