```cpp
#pragma once

#include <array>
#include <cstddef>
#include <reaction/memory/sbo_resource.h>

namespace test_reaction {

struct SmallPayload {
    int value;
    bool operator!=(const SmallPayload& other) const = default;
};

struct LargePayload {
    std::array<int, 64> data{};
    bool operator!=(const LargePayload& other) const = default;
};

struct SboStorageStatus {
    bool updateReportedChange;
    bool smallUsingSBO;
    std::size_t smallStackUsage;
    bool largeInitialized;
    bool largeUsingSBO;
};

SboStorageStatus test_sbo_storage_info(int initialSmall,
                                       int updatedSmall,
                                       int largeSeed) {
    SboStorageStatus status{};

    // 1. Create a lambda function to make large payload
    auto makeLargePayload = [largeSeed]() -> LargePayload {
        LargePayload payload;
        for (size_t i = 0; i < payload.data.size(); ++i) {
            payload.data[i] = largeSeed + static_cast<int>(i);
        }
        return payload;
    };

    // 2. Create small SBOResource
    auto smallResource = std::make_shared<reaction::memory::SBOResource<SmallPayload>>(
        SmallPayload{initialSmall});

    // 3. Create large SBOResource
    auto largeResource = std::make_shared<reaction::memory::SBOResource<LargePayload>>(
        makeLargePayload());
    status.largeInitialized = true;

    // 4. Update small resource value and check if change was reported
    status.updateReportedChange = smallResource->updateValue(SmallPayload{updatedSmall});

    // 5. Get storage information for small resource
    status.smallUsingSBO = smallResource->isUsingSBO();
    status.smallStackUsage = smallResource->getStackUsage();

    // 6. Get storage information for large resource
    status.largeUsingSBO = largeResource->isUsingSBO();

    return status;
}

}  // namespace test_reaction
```

