#pragma once

#include <reaction/core/exception.h>
#include <string>

namespace test_reaction {

struct ExceptionInfo {
    std::string formattedMessage;
    std::string originalMessage;
    std::string file;
    int line;
    std::string function;
    std::string codeName;
};

/**
 * Function: Capture metadata from a ReactionException instance.
 *
 * @param message Error message to embed
 * @param code ReactionException error code
 * @param file Source file metadata
 * @param line Line number metadata
 * @param function Function name metadata
 * @return ExceptionInfo Snapshot of stored information
 */
inline ExceptionInfo capture_exception_info(const std::string &message,
    reaction::ReactionException::ErrorCode code,
    const std::string &file,
    int line,
    const std::string &function) {
    reaction::ReactionException ex(message, code, file, line, function);

    ExceptionInfo info;
    info.formattedMessage = ex.what();
    info.originalMessage = ex.getOriginalMessage();
    info.file = ex.getFile();
    info.line = ex.getLine();
    info.function = ex.getFunction();
    info.codeName = reaction::ReactionException::errorCodeToString(ex.getErrorCode());
    return info;
}

}  // namespace test_reaction

test cases:
#include <gtest/gtest.h>

#include "test_exception_metadata.hpp"

namespace test_reaction {

/**
 * Test Case: Validate ReactionException metadata accessors.
 *
 * Test Scenario:
 * - Create a ReactionException with explicit metadata
 * - Ensure getters expose original message, file, line, function, and code string
 */
TEST(reaction, test_exception_metadata) {
  const std::string message = "Critical failure";
  const std::string file = "engine/core.cpp";
  const std::string function = "performWork";
  const int line = 77;

  const auto info = capture_exception_info(
      message,
      reaction::ReactionException::ErrorCode::INVALID_STATE,
      file,
      line,
      function);

  EXPECT_EQ(info.originalMessage, message);
  EXPECT_EQ(info.file, file);
  EXPECT_EQ(info.line, line);
  EXPECT_EQ(info.function, function);
  EXPECT_EQ(info.codeName, "INVALID_STATE");
  EXPECT_NE(info.formattedMessage.find(file), std::string::npos);
  EXPECT_NE(info.formattedMessage.find("INVALID_STATE"), std::string::npos);
}

}  // namespace test_reaction

