TEST(reaction, test_graph_reset_node) {
  const auto result = test_graph_reset_node("source", "target");

  EXPECT_TRUE(result.notifiedBeforeReset);
  EXPECT_FALSE(result.notifiedAfterReset);
}

}  // namespace test_reaction

