TEST(reaction, test_field_graph_cleanup) {
  constexpr uint64_t objectId = 42;

  const auto result = test_field_graph_cleanup(objectId);

  EXPECT_TRUE(result.notifiedBeforeDelete);
  EXPECT_FALSE(result.notifiedAfterDelete);
}

