    constexpr size_t LARGE_GUARD_SIZE = 8192; // 8KB guard
    reaction::memory::StackGuard<LARGE_GUARD_SIZE> largeGuard;

    // 7. Check if guard succeeded
    snapshot.guardHeld = largeGuard.isHeld();

    // 8. Check if allocation blocked while guard is held
    if (snapshot.guardHeld) {
        // Try to allocate a small object while guard is active
        constexpr size_t SMALL_GUARD_SIZE = 1024; // 1KB guard
        reaction::memory::StackGuard<SMALL_GUARD_SIZE> smallGuard;
        snapshot.allocationBlockedWhileGuardHeld = !smallGuard.isHeld();
    } else {
