    int afterShift = calc.get();

    // 12. Apply post-increment
    int postIncReturn = counter++;

    // 13. Get final value
    int finalVal = calc.get();

    // 14. Return atomic compound snapshot
    return AtomicCompoundSnapshot{
        afterAdd,
        afterMult, 
        afterAnd,
        afterShift,
        postIncReturn,
        finalVal,
        calcEvalCount
    };
}

}  // namespace test_reaction
